/**
 * Per-night telemetry from the LLM clustering pass. The script
sometimes drops clusters (bad shape, hallucinated signal ids)
before they ever reach the queue, so a quiet queue can be
either "model returned little" or "model returned plenty but
we threw most of it away". Editors look at this badge to tell
the difference.

 */
export interface TrendClusterRunSummary {
  /** When the clustering pass finished writing. */
  finishedAt: string;
  /** Number of chunks the script attempted in this run. */
  chunksTotal: number;
  /** Chunks where the LLM call threw (rate limit, transient
5xx, malformed JSON). These don't contribute to the
counts below.
 */
  chunksFailed: number;
  /** Sum across surviving chunks of clusters the model
returned, before any schema or hallucination filtering.
 */
  modelReturnedTotal: number;
  /** Clusters dropped because they failed the schema guards
(bad verdict / tier / template, short name, single
signal, non-integer ids).
 */
  schemaRejectedTotal: number;
  /** Clusters dropped because too many of their signal ids
weren't in the batch we sent — i.e. the model invented
ids and the cluster fell below the min-signals floor
after filtering them out.
 */
  hallucinationDroppedTotal: number;
  /** Candidate rows actually inserted into `trend_candidates`
on this run. Same number the script logs as "total
candidates" at the end.
 */
  candidatesCreatedTotal: number;
  /** `(schemaRejectedTotal + hallucinationDroppedTotal) /
modelReturnedTotal`, rounded to two decimals. 0 when the
model returned nothing. The reviewer queue UI flashes a
warning banner when this is above 0.5.
 */
  rejectionRate: number;
  /** Optional tag for unusual run states. Set to `no_signals`
when the run had nothing to cluster.
 */
  note?: string | null;
}

